#include <bits/stdc++.h>
using namespace std;

int n, q, a[1000005];
int l, r, k;
int s[1000005];

int main() {
    cin >> n >> q;
    for (int i = 1; i <= n; i++) {
        scanf("%d", a + i);
        s[i] = s[i - 1] + a[i];
    }
    while (q--) {
        scanf("%d %d %d", &l, &r, &k);
        if (k <= r - l) {
            int cnt = s[r] - s[l - 1];
            if (k == r - l) {
                if (r - l + 1 == cnt) {
                    printf("0\n");
                }
                else {
                    printf("%d\n", int(abs(cnt - k)));
                }
            }
            else if (k < r - l) {
                printf("%d\n", int(abs(cnt - k)));
            }
        }
        else {
            printf("-1\n");
        }
    }
    return 0;
}
